import json
import time
from typing import Optional, Dict, Any, List
from dataclasses import dataclass
from enum import Enum

# Cricket-themed Agentic Workflow Example

class MatchPhase(Enum):
    POWERPLAY = "powerplay"
    MIDDLE_OVERS = "middle_overs"
    DEATH_OVERS = "death_overs"

class BowlerType(Enum):
    PACE = "pace"
    SPIN = "spin"
    ALLROUNDER = "allrounder"

@dataclass
class CricketPlayer:
    name: str
    role: str
    batting_avg: float
    bowling_economy: float
    current_innings: int = 0
    balls_faced: int = 0
    runs_scored: int = 0

@dataclass
class MatchState:
    target: int
    current_runs: int
    overs_bowled: float
    wickets_lost: int
    batsmen: List[CricketPlayer]
    bowlers: List[CricketPlayer]
    phase: MatchPhase

