                "latency_ms": 150,
                "timeout_ms": 5000,
                "fallback": "use_cached_stats",
                "impl": self._fetch_player_stats
            },
            "fetch_match_conditions": {
                "description": "Get current pitch, weather, and field data",
                "latency_ms": 200,
                "timeout_ms": 5000,
                "fallback": "use_last_known_conditions",
