        if tool_name not in self.tools:
            return {"error": f"Tool {tool_name} not found"}

        tool = self.tools[tool_name]
        try:
            start_time = time.time()
            result = tool["impl"](**kwargs)
            execution_time = (time.time() - start_time) * 1000
            result["execution_time_ms"] = execution_time
            return result
        except Exception as e:
            return {"error": str(e), "fallback_action": tool["fallback"]}

class AdvancedCricketAgent:
    """Advanced agent with caching, context management, and parallelization."""

    def __init__(self, model_name: str = "gpt-4-turbo", context_tokens: int = 8000):
        self.model_name = model_name
        self.context_window = ContextWindow(max_tokens=context_tokens)
        self.result_cache = ResultCache(ttl_seconds=300)
        self.tool_registry = CricketToolRegistry()
        self.execution_frames: List[ExecutionFrame] = []
        self.step_counter = 0

    def reasoning_step(self, current_observation: Dict[str, Any]) -> str:
        """Simulates LLM reasoning using current observation and cached memory."""
        # Add observation to context
        obs_json = json.dumps(current_observation)
        self.context_window.add_message(
            role="system",
            content=f"Current match state: {obs_json}",
            estimated_tokens=len(obs_json) // 4
        )

        # In real implementation, this would call an LLM API
        # Here, we simulate deterministic reasoning based on observation
        reasoning = f"""
        Analysis:
        - Current run rate: {current_observation.get('run_rate', 0):.1f}
        - Overs remaining: {current_observation.get('overs_remaining', 0)}
        - Phase: {current_observation.get('phase', 'unknown')}

        Reasoning: Match situation suggests need for {self._determine_strategy(current_observation)}
        """

        return reasoning.strip()

    def _determine_strategy(self, obs: Dict[str, Any]) -> str:
        run_rate = obs.get('run_rate', 0)
        phase = obs.get('phase', '')

        if phase == 'powerplay' and run_rate < 7:
            return 'aggressive acceleration'
        elif phase == 'death_overs' and run_rate > 8:
            return 'controlled aggression'
        else:
            return 'balanced accumulation'

    def execute_with_caching(self, tool_name: str, parameters: Dict[str, Any]) -> Dict[str, Any]:
        """Execute tool invocation with caching."""
        # Check cache first
        cached_result = self.result_cache.get(tool_name, parameters)
        if cached_result:
            return {**cached_result, "cache_hit": True}

        # Cache miss: invoke tool
        result = self.tool_registry.invoke(tool_name, **parameters)

        # Store in cache
        if "error" not in result:
            self.result_cache.put(tool_name, parameters, result)

        result["cache_hit"] = False
        return result

    def run_step(self, observation: Dict[str, Any]) -> ExecutionFrame:
        """Execute a single agent step with caching and memory management."""
        self.step_counter += 1

        # Observation hashing for deduplication
        obs_hash = hashlib.md5(json.dumps(observation, sort_keys=True).encode()).hexdigest()

        # Reasoning step
        reasoning = self.reasoning_step(observation)

        # Action selection (simulated LLM output parsing)
        action_selected = self._select_action(observation)

        # Extract tool parameters
        tool_parameters = self._extract_parameters(observation, action_selected)

        # Execute with caching
        start_time = time.time()
        tool_result = self.execute_with_caching(
            tool_name=action_selected,
            parameters=tool_parameters
        )
        execution_time = (time.time() - start_time) * 1000

        # Create execution frame
        frame = ExecutionFrame(
            step_id=self.step_counter,
            observation_hash=obs_hash,
            reasoning=reasoning,
            action_selected=action_selected,
            tool_parameters=tool_parameters,
            tool_result=tool_result,
            execution_time_ms=execution_time,
            cache_hit=tool_result.get("cache_hit", False)
        )

        self.execution_frames.append(frame)
        return frame

    def _select_action(self, obs: Dict[str, Any]) -> str:
        """Action selection based on observation (simulated)."""
        phase = obs.get('phase', 'middle_overs')

        if phase == 'powerplay':
            return 'invoke_batting_strategy'
        elif phase == 'death_overs':
            return 'invoke_bowling_rotation'
        else:
            return 'fetch_match_conditions'

    def _extract_parameters(self, obs: Dict[str, Any], action: str) -> Dict[str, Any]:
        """Extract parameters for tool invocation."""
        if action == 'invoke_batting_strategy':
            return {
                "strategy": "aggressive" if obs.get('run_rate', 0) > 7 else "conservative",
                "batsman": "Rohit Sharma"
            }
        elif action == 'invoke_bowling_rotation':
            return {
                "bowler": "Jasprit Bumrah",
                "over_number": obs.get('overs_bowled', 0)
            }
        else:
            return {}

    def print_execution_summary(self):
        """Print detailed execution trace for debugging."""
        print("\n=== Execution Summary ===")
        print(f"Total steps: {self.step_counter}")
        print(f"Cache stats: {self.result_cache.get_stats()}")
        print(f"Context window usage: {self.context_window.current_tokens}/{self.context_window.max_tokens} tokens\n")

        for frame in self.execution_frames:
            print(f"Step {frame.step_id}:")
            print(f"  Action: {frame.action_selected}")
            print(f"  Execution time: {frame.execution_time_ms:.1f}ms")
            print(f"  Cache hit: {frame.cache_hit}")
            if frame.tool_result and "error" not in frame.tool_result:
                print(f"  Result: {frame.tool_result}")
            print()

